import { useState, useEffect } from "react";
import "./Tasks.css";

export default function Tasks() {
  const [title, setTitle] = useState("");
  const [description, setDescription] = useState("");
  const [priority, setPriority] = useState("Low");
  const [dueDate, setDueDate] = useState("");
  const [search, setSearch] = useState("");

  const [tasks, setTasks] = useState([]);
  const [editId, setEditId] = useState(null);
  const [filter, setFilter] = useState("all");

  useEffect(() => {
    const savedTasks = JSON.parse(localStorage.getItem("tasks")) || [];
    setTasks(savedTasks);
  }, []);

  useEffect(() => {
    localStorage.setItem("tasks", JSON.stringify(tasks));
  }, [tasks]);

  const handleSubmit = () => {
    if (!title.trim()) return;

    if (editId !== null) {
      setTasks((prev) =>
        prev.map((t) =>
          t.id === editId
            ? { ...t, title, description, priority, dueDate }
            : t
        )
      );
      setEditId(null);
    } else {
      setTasks((prev) => [
        ...prev,
        {
          id: Date.now(),
          title,
          description,
          priority,
          dueDate,
          completed: false,
          createdAt: new Date().toLocaleString(),
        },
      ]);
    }

    setTitle("");
    setDescription("");
    setPriority("Low");
    setDueDate("");
  };

  const handleEdit = (t) => {
    setTitle(t.title || t.text || ""); 
    setDescription(t.description || "");
    setPriority(t.priority || "Low");
    setDueDate(t.dueDate || "");
    setEditId(t.id);
  };
  const handleDelete = (id) => {
    setTasks((prev) => prev.filter((t) => t.id !== id));
  };
  const handleToggle = (id) => {
    setTasks((prev) =>
      prev.map((t) =>
        t.id === id ? { ...t, completed: !t.completed } : t
      )
    );
  };
  const filteredTasks = tasks.filter((t) => {
    const matchesFilter =
      filter === "completed"
        ? t.completed
        : filter === "pending"
        ? !t.completed
        : true;

    const matchesSearch =
      (t.title || t.text || "")
        .toLowerCase()
        .includes(search.toLowerCase());

    return matchesFilter && matchesSearch;
  });

  return (
    <div className="tasks-container">
      <h2> Task Manager</h2>
      <input
        type="text"
        placeholder="Search tasks..."
        value={search}
        onChange={(e) => setSearch(e.target.value)}
      />
      <input
        type="text"
        placeholder="Title"
        value={title}
        onChange={(e) => setTitle(e.target.value)}
      />

      <input
        type="text"
        placeholder="Description"
        value={description}
        onChange={(e) => setDescription(e.target.value)}
      />

      <select value={priority} onChange={(e) => setPriority(e.target.value)}>
        <option>Low</option>
        <option>Medium</option>
        <option>High</option>
      </select>

      <input
        type="date"
        value={dueDate}
        onChange={(e) => setDueDate(e.target.value)}
      />

      <button onClick={handleSubmit}>
        {editId !== null ? "Update" : "Add"}
      </button>
      <div className="filter-buttons">
        <button onClick={() => setFilter("all")}>All</button>
        <button onClick={() => setFilter("completed")}>Completed</button>
        <button onClick={() => setFilter("pending")}>Pending</button>
      </div>

      <button onClick={() => setTasks([])}>Clear All</button>
      <ul>
        {filteredTasks.length === 0 ? (
          <p>No tasks found</p>
        ) : (
          filteredTasks.map((t) => (
            <li key={t.id}>
              <h3>{t.title || t.text}</h3>
              <p>{t.description}</p>
              <p>Priority: {t.priority}</p>
              <p>Due: {t.dueDate}</p>
              <small>{t.createdAt}</small>

              <div>
                <button onClick={() => handleToggle(t.id)}>✔</button>
                <button onClick={() => handleEdit(t)}>✏️</button>
                <button onClick={() => handleDelete(t.id)}>❌</button>
              </div>
            </li>
          ))
        )}
      </ul>
    </div>
  );
}
